function renderDashboard(){
  document.getElementById('view-tabs').innerHTML='';
  document.getElementById('rp-head').textContent='intelX — Morocco 2026';
  const local=getSeats();
  const regional=getLRNationalSeats();
  const combined=getCombinedSeats();
  const sortedComb=Object.entries(combined).filter(([,v])=>v>0).sort((a,b)=>b[1]-a[1]);
  const total=TOTAL();
  const maj=MAJ();
  const leader=sortedComb[0]?.[0]||'—';
  const leaderN=sortedComb[0]?.[1]||0;
  const tossups=Object.entries(D).filter(([n,d])=>getStatus(d.m,n,d)==='tossup');
  const tossupSeats=tossups.reduce((a,[,d])=>a+d.s,0);
  const isCustomSim=simResults&&!simResults._baseline;

  // Region filter: scope data if region selected
  const scopedD=selRegion?Object.fromEntries(Object.entries(D).filter(([,d])=>d.r===selRegion)):D;
  const scopedDistCount=Object.keys(scopedD).length;
  const scopedSeats=Object.values(scopedD).reduce((a,d)=>a+d.s,0);

  // Top competitive districts (scoped)
  const topCompet=Object.entries(scopedD).map(([n,d])=>({n,d,cs:compScore(n,d),st:getStatus(d.m,n,d)}))
    .sort((a,b)=>a.cs-b.cs).slice(0,6);

  // Party performance in scoped area
  const scopedVotes={};
  let scopedTot=0;
  Object.values(scopedD).forEach(d=>{
    const tot=Object.values(d.v).reduce((a,b)=>a+b,0)||0;
    scopedTot+=tot;
    Object.entries(d.v).forEach(([p,v])=>{scopedVotes[p]=(scopedVotes[p]||0)+v;});
  });

  // Recent sim votes — aggregate projected votes from sim
  const simVotes={};
  if(simResults){
    MAJOR.forEach(p=>{
      let vTotal=0;
      Object.entries(scopedD).forEach(([name,d])=>{
        const simD=simResults[name];
        const tot=Object.values(d.v).reduce((a,b)=>a+b,0)||1;
        if(simD&&simD.adj){vTotal+=(simD.adj[p]||0);}
        else{
          const effTo=simD?1:1;
          vTotal+=(d.v[p]||0);
        }
      });
      simVotes[p]=Math.round(vTotal);
    });
  }

  const html=`
  <!-- Top KPI strip -->
  <div class="stat-grid" style="grid-template-columns:repeat(6,1fr);margin-bottom:14px">
    <div class="stat-box" style="background:var(--navy);border-color:var(--navy)">
      <div class="stat-label" style="color:#a8d4e8">Total seats</div>
      <div class="stat-val" style="color:#fff">${total}</div>
      <div class="stat-sub" style="color:#a8d4e8">305 local + 90 régionales</div>
    </div>
    <div class="stat-box" style="background:var(--navy);border-color:var(--navy)">
      <div class="stat-label" style="color:#a8d4e8">Majorité</div>
      <div class="stat-val" style="color:#fff">${maj}</div>
      <div class="stat-sub" style="color:#a8d4e8">sièges requis</div>
    </div>
    <div class="stat-box">
      <div class="stat-label">Leader projeté</div>
      <div class="stat-val" style="color:${pc(leader)}">${leader}</div>
      <div class="stat-sub">${leaderN} sièges combinés</div>
    </div>
    <div class="stat-box">
      <div class="stat-label">Majorité?</div>
      <div class="stat-val" style="color:${leaderN>=maj?'var(--green)':'var(--red)'}">
        ${leaderN>=maj?'✓ OUI':'✗ NON'}
      </div>
      <div class="stat-sub">${leaderN>=maj?'+'+( leaderN-maj)+' au-dessus':maj-leaderN+' manquants'}</div>
    </div>
    <div class="stat-box">
      <div class="stat-label">Toss-ups</div>
      <div class="stat-val" style="color:var(--red)">${tossups.length}</div>
      <div class="stat-sub">${tossupSeats} sièges &lt;3pp</div>
    </div>
    <div class="stat-box" style="background:${isCustomSim?'var(--teal-bg)':'var(--surface2)'}">
      <div class="stat-label">Simulation</div>
      <div class="stat-val" style="font-size:14px;color:${isCustomSim?'var(--teal)':'var(--text3)'}">
        ${isCustomSim?'Active':'Baseline'}
      </div>
      <div class="stat-sub">${isCustomSim?(simResults._runs||0).toLocaleString()+' runs':'Prévision 10k runs'}</div>
    </div>
  </div>

  <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:12px">

    <!-- Combined seat projection -->
    <div class="card">
      <div class="card-title" style="display:flex;justify-content:space-between">
        <span>Projection combinée — Locales + Régionales</span>
        <span style="font-size:10px;color:var(--teal);font-weight:600;cursor:pointer" onclick="setTopTab('forecast')">Locales →</span>
      </div>
      <div class="seat-bar" style="height:20px;margin-bottom:10px">
        ${sortedComb.map(([p,n])=>`<div style="width:${(n/total*100).toFixed(1)}%;background:${pc(p)}" title="${p}: ${n}"></div>`).join('')}
      </div>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:3px">
        ${sortedComb.filter(([,v])=>v>0).map(([p,n])=>{
          const loc=local[p]||0; const reg=regional[p]||0;
          const b=HIST_NAT['2021'][p]||0; const delta=loc-b;
          return `<div style="display:flex;align-items:center;gap:5px;padding:4px 6px;border-radius:5px;background:${pc(p)}08">
            <div style="width:8px;height:8px;border-radius:2px;background:${pc(p)};flex-shrink:0"></div>
            <span style="font-size:11px;font-weight:700;color:${pc(p)};min-width:28px">${p}</span>
            <span style="font-size:14px;font-weight:800;color:var(--navy);min-width:24px">${n}</span>
            <span style="font-size:9px;color:var(--text3)">${loc}L+${reg}R</span>
            <span style="font-size:10px;font-weight:600;color:${delta>0?'var(--green)':delta<0?'var(--red)':'var(--text3)'}; margin-left:auto">${delta>=0?'+':''}${delta}</span>
          </div>`;
        }).join('')}
      </div>
      <div style="margin-top:10px;padding-top:8px;border-top:1px solid var(--border);display:flex;gap:8px">
        <div style="flex:1;text-align:center;padding:6px;background:var(--surface2);border-radius:5px">
          <div style="font-size:10px;color:var(--text3)">Locales</div>
          <div style="font-size:16px;font-weight:800;color:var(--navy)">305</div>
        </div>
        <div style="flex:1;text-align:center;padding:6px;background:var(--teal-bg);border-radius:5px;cursor:pointer" onclick="setTopTab('lr')">
          <div style="font-size:10px;color:var(--teal)">Régionales</div>
          <div style="font-size:16px;font-weight:800;color:var(--teal)">90</div>
        </div>
        <div style="flex:1;text-align:center;padding:6px;background:${leaderN>=maj?'var(--green-bg)':'var(--red-bg)'};border-radius:5px">
          <div style="font-size:10px;color:${leaderN>=maj?'var(--green)':'var(--red)'}">Majorité</div>
          <div style="font-size:16px;font-weight:800;color:${leaderN>=maj?'var(--green)':'var(--red)'}">${maj}</div>
        </div>
      </div>
    </div>

    <!-- Coalition calculator -->
    <div class="card">
      <div class="card-title">Coalitions possibles</div>
      ${(()=>{
        const s=sortedComb;
        if(!s.length)return '';
        const [lp,ln]=s[0]; const s2=s[1]; const s3=s[2]; const s4=s[3];
        const scenarios=[
          {l:`${lp} seul`,n:ln,col:lp},
          s2?{l:`${lp} + ${s2[0]}`,n:ln+s2[1],col:lp}:null,
          s2&&s3?{l:`${lp} + ${s2[0]} + ${s3[0]}`,n:ln+s2[1]+s3[1],col:lp}:null,
          s2&&s3&&s4?{l:`+ ${s4[0]}`,n:ln+s2[1]+s3[1]+s4[1],col:lp}:null,
        ].filter(Boolean);
        return scenarios.map(sc=>{
          const ok=sc.n>=maj; const pct=Math.min(100,sc.n/maj*100);
          return `<div class="coal-row">
            <span class="coal-n" style="color:${ok?'var(--green)':'var(--navy)'}">${sc.n}</span>
            <div class="coal-bar"><div class="coal-fill" style="width:${pct.toFixed(0)}%;background:${ok?'var(--green)':'var(--border2)'}"></div></div>
            <span class="coal-lbl">${sc.l}</span>
            <span class="coal-st" style="color:${ok?'var(--green)':'var(--red)'}">${ok?'MAJ':'−'+(maj-sc.n)}</span>
          </div>`;
        }).join('');
      })()}
    </div>
  </div>

  <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:12px;margin-bottom:12px">

    <!-- Top competitive districts -->
    <div class="card">
      <div class="card-title" style="display:flex;justify-content:space-between">
        <span>Circonscriptions clés${selRegion?' — '+selRegion.split(' - ')[0]:''}</span>
        <span style="font-size:10px;color:var(--teal);cursor:pointer" onclick="setTopTab('battleground')">Voir tout →</span>
      </div>
      ${topCompet.map(({n,d,cs,st})=>{
        const allW=rankBySeats(d.v,d.s);
        const simD=simResults&&simResults[n];
        const proj=simD?(simD.seats?.[0]||d.w21):d.w21;
        return `<div style="display:flex;align-items:center;gap:6px;padding:6px 0;border-bottom:1px solid var(--border);cursor:pointer" onclick="selectDist('${n.replace(/'/g,"\\'")}')">
          <span class="pill ${statusPillClass(st)}" style="font-size:9px;min-width:24px">${cs.toFixed(1)}</span>
          <div style="flex:1;min-width:0">
            <div style="font-size:11px;font-weight:600;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${n}</div>
            <div style="font-size:10px;color:var(--text3)">${d.s}s · +${d.m}pp</div>
          </div>
          <span style="font-size:10px;font-weight:700;color:${pc(proj)}">${proj}</span>
        </div>`;
      }).join('')}
    </div>

    <!-- Projected votes by party (scoped) -->
    <div class="card">
      <div class="card-title">Voix projetées${selRegion?' — '+selRegion.split(' - ')[0]:' — National'}</div>
      ${Object.entries(scopedVotes).sort((a,b)=>b[1]-a[1]).slice(0,8).map(([p,v])=>{
        const pct=(v/scopedTot*100).toFixed(1);
        const simV=simVotes[p];
        const delta=simV?Math.round(simV-v):null;
        return `<div style="display:flex;align-items:center;gap:6px;padding:3px 0">
          <div style="width:7px;height:7px;border-radius:2px;background:${pc(p)};flex-shrink:0"></div>
          <span style="font-size:11px;font-weight:700;color:${pc(p)};min-width:28px">${p}</span>
          <div style="flex:1;height:5px;background:var(--border);border-radius:3px">
            <div style="height:100%;width:${pct}%;background:${pc(p)};border-radius:3px;max-width:100%"></div>
          </div>
          <span style="font-size:10px;min-width:34px;text-align:right">${pct}%</span>
          <span style="font-size:10px;color:var(--text3);min-width:62px;text-align:right">${v.toLocaleString()}</span>
          ${delta!==null&&isCustomSim?`<span style="font-size:9px;color:${delta>0?'var(--green)':'var(--red)'};min-width:44px">${delta>=0?'+':''}${delta.toLocaleString()}</span>`:''}
        </div>`;
      }).join('')}
    </div>

    <!-- Alerts & key signals -->
    <div class="card">
      <div class="card-title">Signaux clés</div>
      ${renderAlerts(combined)}
      <div class="divider"></div>
      <div style="font-size:10px;font-weight:700;color:var(--text3);text-transform:uppercase;letter-spacing:.07em;margin-bottom:6px">Actions rapides</div>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:5px">
        ${['forecast','lr','h2h','simdetails','party','strategic'].map((t,i)=>{
          const labels={forecast:'Forecast',lr:'Listes Rég.',h2h:'Head-to-Head',simdetails:'Sim Details',party:'Party Profile',strategic:'Strategic'};
          return `<button onclick="setTopTab('${t}')" style="padding:7px 4px;font-size:11px;font-weight:600;background:var(--surface2);border:1px solid var(--border);border-radius:5px;cursor:pointer;font-family:Inter,sans-serif;color:var(--navy)">${labels[t]}</button>`;
        }).join('')}
      </div>
    </div>
  </div>

  <!-- Charts section with filter -->
  <div class="card" style="margin-top:12px">
    <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:12px;flex-wrap:wrap;gap:8px">
      <div class="card-title" style="margin:0">Analyse visuelle — Performance des partis</div>
      <div style="display:flex;gap:6px;flex-wrap:wrap">
        <select id="dash-chart-filter" onchange="renderDashboardCharts()" style="font-size:11px;padding:4px 8px;border:1px solid var(--border);border-radius:4px;font-family:Inter,sans-serif;background:var(--surface2)">
          <option value="national">National</option>
          ${selRegion?`<option value="region" selected>${selRegion.split(' - ')[0]}</option>`:Object.keys({...Object.fromEntries(Object.values(D).map(d=>[d.r,1]))}).map(r=>`<option value="${r}">${r.split(' - ')[0]}</option>`).join('')}
        </select>
        <select id="dash-chart-type" onchange="renderDashboardCharts()" style="font-size:11px;padding:4px 8px;border:1px solid var(--border);border-radius:4px;font-family:Inter,sans-serif;background:var(--surface2)">
          <option value="seats">Sièges 2021 vs 2026</option>
          <option value="votes">Part des voix</option>
          <option value="delta">Δ Évolution</option>
        </select>
      </div>
    </div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:14px">
      <div>
        <div style="font-size:10px;font-weight:700;color:var(--text3);text-transform:uppercase;letter-spacing:.07em;margin-bottom:6px">Sièges — Comparaison 2021 / 2026</div>
        <div style="height:200px;position:relative"><canvas id="dash-chart-seats"></canvas></div>
      </div>
      <div>
        <div style="font-size:10px;font-weight:700;color:var(--text3);text-transform:uppercase;letter-spacing:.07em;margin-bottom:6px">Part des voix 2021</div>
        <div style="height:200px;position:relative"><canvas id="dash-chart-votes"></canvas></div>
      </div>
    </div>
  </div>`;

  document.getElementById('view-content').innerHTML=html;
  renderRightPanel();
  setTimeout(renderDashboardCharts,80);
}

// ─────────────────────────── DASHBOARD CHARTS ───────────────────────────
function renderDashboardCharts(){
  if(!window.Chart)return;
  const combined=getCombinedSeats();
  const hist=HIST_NAT;
  const chartFilter=document.getElementById('dash-chart-filter')?.value||'national';
  const scopedD=chartFilter!=='national'
    ? Object.fromEntries(Object.entries(D).filter(([,d])=>d.r===chartFilter))
    : (selRegion?Object.fromEntries(Object.entries(D).filter(([,d])=>d.r===selRegion)):D);
  const parties=MAJOR.filter(p=>(combined[p]||0)>0||(hist['2021'][p]||0)>0);

  // Chart 1: Seats 2021 vs 2026
  const c1=document.getElementById('dash-chart-seats');
  if(c1){
    if(c1._ci)c1._ci.destroy();
    // Compute local seats by party for scoped districts
    const localScoped={};MAJOR.forEach(p=>{localScoped[p]=0;});
    Object.entries(scopedD).forEach(([n,d])=>{
      const w=simResults?getSimWinner(n):d.w21;
      if(w)localScoped[w]=(localScoped[w]||0)+1;
    });
    const hist21Scoped={};MAJOR.forEach(p=>{hist21Scoped[p]=0;});
    Object.values(scopedD).forEach(d=>{if(d.w21)hist21Scoped[d.w21]=(hist21Scoped[d.w21]||0)+1;});
    const filtParties=parties.filter(p=>(localScoped[p]||0)>0||(hist21Scoped[p]||0)>0);
    c1._ci=new Chart(c1,{
      type:'bar',
      data:{
        labels:filtParties,
        datasets:[
          {label:'2021',data:filtParties.map(p=>hist21Scoped[p]||0),backgroundColor:filtParties.map(p=>pc(p)+'55'),borderColor:filtParties.map(p=>pc(p)),borderWidth:1.5,borderRadius:3},
          {label:'2026 proj.',data:filtParties.map(p=>localScoped[p]||0),backgroundColor:filtParties.map(p=>pc(p)),borderColor:filtParties.map(p=>pc(p)),borderWidth:1,borderRadius:3}
        ]
      },
      options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{labels:{font:{size:10},color:'#4a5a6b',boxWidth:10}}},scales:{y:{beginAtZero:true,ticks:{font:{size:10},color:'#8a96a3'},grid:{color:'#dde2e811'}},x:{ticks:{font:{size:10},color:'#4a5a6b'},grid:{display:false}}}}
    });
  }

  // Chart 2: Vote share doughnut
  const c2=document.getElementById('dash-chart-votes');
  if(c2){
    if(c2._ci)c2._ci.destroy();
    const voteByParty={};let totalV=0;
    Object.values(scopedD).forEach(d=>{Object.entries(d.v).forEach(([p,v])=>{voteByParty[p]=(voteByParty[p]||0)+v;totalV+=v;});});
    const top=Object.entries(voteByParty).sort((a,b)=>b[1]-a[1]).slice(0,9);
    c2._ci=new Chart(c2,{
      type:'doughnut',
      data:{
        labels:top.map(([p])=>p),
        datasets:[{data:top.map(([,v])=>+(v/totalV*100).toFixed(1)),backgroundColor:top.map(([p])=>pc(p)+'cc'),borderWidth:1.5,borderColor:top.map(([p])=>pc(p))}]
      },
      options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{position:'right',labels:{font:{size:10},color:'#4a5a6b',padding:5,boxWidth:10}},tooltip:{callbacks:{label:ctx=>`${ctx.label}: ${ctx.parsed}%`}}}}
    });
  }
}


let lrSortCol='region'; let lrSortDir=1;

function renderLRView(){
  document.getElementById('view-tabs').innerHTML='';
  document.getElementById('rp-head').textContent='Listes Régionales';
  const lrData=calcRegionalSeats();

  // National LR totals per party
  const lrNat={};
  MAJOR.forEach(p=>{lrNat[p]=Object.values(lrData).reduce((a,{seats})=>a+(seats[p]||0),0);});
  const lrSorted=Object.entries(lrNat).filter(([,v])=>v>0).sort((a,b)=>b[1]-a[1]);

  // Filter by selected region
  const scopedLR=selRegion
    ? Object.fromEntries(Object.entries(lrData).filter(([,{region}])=>region===selRegion))
    : lrData;

  const rows=Object.entries(scopedLR).map(([lrName,{region,sieges,quotient,votes,seats}])=>{
    const totalV=Object.values(votes).reduce((a,b)=>a+b,0)||1;
    const lrReg=LR[lrName];
    return {lrName,region,sieges,quotient,votes,seats,totalV,inscrits:lrReg?.inscrits||0};
  }).sort((a,b)=>{
    const va=lrSortCol==='region'?a.region:lrSortCol==='sieges'?a.sieges:lrSortCol==='inscrits'?a.inscrits:0;
    const vb=lrSortCol==='region'?b.region:lrSortCol==='sieges'?b.sieges:lrSortCol==='inscrits'?b.inscrits:0;
    return typeof va==='string'?va.localeCompare(vb)*lrSortDir:(va-vb)*lrSortDir;
  });

  const sortBtn=(col,label)=>`<th style="cursor:pointer;user-select:none" onclick="lrSortCol='${col}';lrSortDir=lrSortCol==='${col}'?-lrSortDir:1;renderLRView()">${label}${lrSortCol===col?(lrSortDir>0?' ▲':' ▼'):' ↕'}</th>`;

  const html=`
  <!-- National LR summary -->
  <div class="card" style="margin-bottom:12px">
    <div class="card-title">Répartition nationale — Listes Régionales (90 sièges · Quotient de Hare + Plus Fort Reste)</div>
    <div class="seat-bar" style="height:18px;margin-bottom:8px">
      ${lrSorted.map(([p,n])=>`<div style="width:${(n/90*100).toFixed(1)}%;background:${pc(p)}" title="${p}: ${n}"></div>`).join('')}
    </div>
    <div style="display:flex;gap:10px;flex-wrap:wrap">
      ${lrSorted.map(([p,n])=>`<div style="display:flex;align-items:center;gap:4px">
        <div style="width:8px;height:8px;border-radius:2px;background:${pc(p)}"></div>
        <span style="font-size:11px;font-weight:700;color:${pc(p)}">${p}</span>
        <span style="font-size:13px;font-weight:800;color:var(--navy)">${n}</span>
        <span style="font-size:10px;color:var(--text3)">sièges</span>
      </div>`).join('')}
    </div>
    <div style="margin-top:8px;font-size:10px;color:var(--text3)">
      Méthode: Quotient = Inscrits ÷ Sièges par région. Attribution: sièges entiers d'abord, puis plus forts restes.
      ${simResults&&!simResults._baseline?'<span style="color:var(--teal);font-weight:600"> · Simulation active — swings appliqués aux voix régionales</span>':''}
    </div>
  </div>

  <!-- Region-by-region table -->
  <div class="card" style="padding:0;overflow:hidden">
    <table class="tbl">
      <thead><tr>
        ${sortBtn('region','Région')}
        ${sortBtn('inscrits','Inscrits')}
        ${sortBtn('sieges','Sièges')}
        <th>Quotient</th>
        ${MAJOR.map(p=>`<th style="color:${pc(p)};cursor:pointer" onclick="lrSortCol='${p}';lrSortDir*=-1;renderLRView()">${p}${lrSortCol===p?(lrSortDir>0?' ▲':' ▼'):''}</th>`).join('')}
        <th>Gagnant</th>
      </tr></thead>
      <tbody>
        ${rows.map(({lrName,region,sieges,quotient,votes,seats,totalV,inscrits})=>{
          const winner=Object.entries(seats).sort((a,b)=>b[1]-a[1])[0];
          return `<tr>
            <td style="font-weight:700">${lrName}</td>
            <td style="font-family:'JetBrains Mono',monospace;font-size:11px">${inscrits.toLocaleString()}</td>
            <td style="text-align:center;font-weight:700">${sieges}</td>
            <td style="font-family:'JetBrains Mono',monospace;font-size:11px">${Math.round(quotient).toLocaleString()}</td>
            ${MAJOR.map(p=>{
              const v=votes[p]||0;
              const s=seats[p]||0;
              const pct=(v/totalV*100).toFixed(1);
              return `<td style="text-align:center">
                ${v>0?`<div style="font-size:11px;font-weight:${s>0?'700':'400'};color:${s>0?pc(p):'var(--text3)'}">${pct}%</div>
                <div style="font-size:10px;color:${s>0?pc(p):'var(--text4)'}">${s>0?s+'s':'—'}</div>`:'<span style="color:var(--text4)">—</span>'}
              </td>`;
            }).join('')}
            <td>${winner?`<span style="font-weight:700;color:${pc(winner[0])}">${winner[0]} <span style="font-size:10px">(${winner[1]}s)</span></span>`:'—'}</td>
          </tr>`;
        }).join('')}
      </tbody>
    </table>
  </div>

  <!-- Per-region detailed breakdown -->
  <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-top:12px">
    ${rows.map(({lrName,region,sieges,quotient,votes,seats,totalV,inscrits})=>{
      const ranked=Object.entries(votes).filter(([,v])=>v>0).sort((a,b)=>b[1]-a[1]);
      const winner=Object.entries(seats).sort((a,b)=>b[1]-a[1])[0];
      return `<div class="card" style="padding:12px">
        <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:8px">
          <div>
            <div style="font-size:12px;font-weight:800;color:var(--navy)">${lrName}</div>
            <div style="font-size:10px;color:var(--text3)">${inscrits.toLocaleString()} inscrits · ${sieges} sièges · Quotient: ${Math.round(quotient).toLocaleString()}</div>
          </div>
          ${winner?`<span style="font-size:11px;font-weight:700;color:${pc(winner[0])}">${winner[0]} leads</span>`:''}
        </div>
        <div class="seat-bar" style="height:10px;margin-bottom:8px">
          ${Object.entries(seats).filter(([,n])=>n>0).sort((a,b)=>b[1]-a[1]).map(([p,n])=>`<div style="width:${(n/sieges*100).toFixed(1)}%;background:${pc(p)}" title="${p}: ${n}s"></div>`).join('')}
        </div>
        ${ranked.slice(0,5).map(([p,v])=>{
          const pct=(v/totalV*100).toFixed(1);
          const s=seats[p]||0;
          const quot=v/quotient;
          return `<div style="display:flex;align-items:center;gap:5px;padding:2px 0;font-size:11px">
            <div style="width:7px;height:7px;border-radius:2px;background:${pc(p)};flex-shrink:0"></div>
            <span style="font-weight:700;color:${pc(p)};min-width:28px">${p}</span>
            <div style="flex:1;height:4px;background:var(--border);border-radius:2px">
              <div style="height:100%;width:${pct}%;background:${pc(p)};border-radius:2px;max-width:100%"></div>
            </div>
            <span style="min-width:36px;text-align:right">${pct}%</span>
            <span style="min-width:52px;text-align:right;color:var(--text3)">${v.toLocaleString()}</span>
            <span style="min-width:28px;font-weight:700;color:${s>0?pc(p):'var(--text4)'}">${s>0?s+'s':'—'}</span>
            <span style="min-width:36px;font-size:10px;color:var(--text3)">(Q${quot.toFixed(2)})</span>
          </div>`;
        }).join('')}
      </div>`;
    }).join('')}
  </div>`;

  document.getElementById('view-content').innerHTML=html;
  renderRightPanel();
}

// ─────────────────────────── SIMULATION DETAILS VIEW ───────────────────────────
let simDetailParty='RNI';
let h2hSortCol='cs'; let h2hSortDir=1;
let simDetailSortCol='name'; let simDetailSortDir=1;

function getSimDistStatus(distName,d,party){
  const allWinners=rankBySeats(d.v,d.s);
  const partyWins=allWinners.includes(party);
  const tot=Object.values(d.v).reduce((a,b)=>a+b,0)||1;
  const sorted=Object.entries(d.v).sort((a,b)=>b[1]-a[1]);
  const partyVotes=d.v[party]||0;
  if(!partyWins){
    const lastWinner=sorted[d.s-1];
    const gap=lastWinner?(lastWinner[1]-partyVotes)/tot*100:100;
    if(gap<3)return'tossup';
    if(gap<8)return'battleground';
    return'absent';
  }
  const simD=simResults&&simResults[distName];
  const meanSeats=simD?simD.meanSeats||{}:{};
  const simChance=meanSeats[party]!==undefined?meanSeats[party]:(partyWins?0.9:0);
  if(simChance<0.35)return'tossup';
  if(simChance<0.6)return'battleground';
  if(simChance<0.85)return'lean';
  return'safe';
}

function simDistPillClass(s){return{tossup:'pill-red',battleground:'pill-amber',lean:'pill-green',safe:'pill-blue',absent:'pill-gray'}[s]||'pill-gray';}
function simDistLabel(s){return{tossup:'Critical',battleground:'Contested',lean:'Leads',safe:'Safe',absent:'Weak'}[s]||s;}

function buildDistAdvantage(distName,d,winner,closeLosers){
  const tot=Object.values(d.v).reduce((a,b)=>a+b,0)||1;
  const sorted=Object.entries(d.v).sort((a,b)=>b[1]-a[1]);
  const winnerVotes=d.v[winner]||0;
  const winnerPct=(winnerVotes/tot*100).toFixed(1);
  const to=TO_MAP[distName]||{};
  const to21=((to.to21||0.45)*100);
  const communes=COMMUNES[distName]||[];
  const histWins=['11','15','16','21'].filter(y=>d['w'+y]===winner).length;
  const histText=histWins>=3?`${winner} has won here in ${histWins}/4 recent elections — a historic stronghold.`:histWins===2?`${winner} won 2 of the last 4 elections here — established but contested.`:`${winner} won here in 2021 but has limited prior history — a recent gain.`;
  const geoText=d.u?`Urban district (${d.r}) — ${winner} benefits from organised urban networks and educated voter base.`:`Rural district (${d.r}) — ${winner} leverages rural community ties and local notables.`;
  const runner=closeLosers[0];
  const gapPp=runner?((winnerVotes-(d.v[runner]||0))/tot*100).toFixed(1):null;
  const leadText=gapPp?`${winner} leads runner-up ${runner} by ${gapPp}pp (${winnerPct}% vs ${((d.v[runner]||0)/tot*100).toFixed(1)}%).`:`${winner} holds ${winnerPct}% of the vote.`;
  const commWon=communes.filter(c=>c.w===winner);
  const commText=communes.length>0?`Wins ${commWon.length}/${communes.length} communes — key strongholds: ${commWon.sort((a,b)=>b.t-a.t).slice(0,3).map(c=>c.n).join(', ')}.`:'';
  const toText=to21<38?`Low turnout (${to21.toFixed(0)}%) amplifies ${winner}'s organisational advantage — strong ground game converts loyalists reliably.`:to21>52?`High turnout (${to21.toFixed(0)}%) signals strong civic mobilisation — ${winner} benefits from broad name recognition.`:`Moderate turnout (${to21.toFixed(0)}%) — competitive ground game is decisive.`;
  return{histText,geoText,leadText,commText,toText};
}

function renderSimulationDetails(){
  document.getElementById('view-tabs').innerHTML='';
  document.getElementById('rp-head').textContent='Simulation Details';
  const focusParties=['RNI','PAM','PI'];
  const partySel=`
    <div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap">
      <span style="font-size:10px;font-weight:700;color:var(--text3);text-transform:uppercase;letter-spacing:.08em;margin-right:2px">Statut par:</span>
      ${MAJOR.map(p=>`<button onclick="simDetailParty='${p}';renderSimulationDetails()" style="padding:3px 11px;font-size:11px;font-weight:700;border-radius:4px;cursor:pointer;font-family:Inter,sans-serif;transition:all .12s;border:2px solid ${pc(p)};background:${simDetailParty===p?pc(p)+'22':'transparent'};color:${pc(p)}">${p}</button>`).join('')}
    </div>`;

  // Sort district entries
  const sortEntry=([name,d])=>{
    if(simDetailSortCol==='name')return name;
    if(simDetailSortCol==='seats')return d.s;
    if(simDetailSortCol==='to')return (TO_MAP[name]||{}).to21||0;
    if(focusParties.includes(simDetailSortCol)){
      const tot=Object.values(d.v).reduce((a,b)=>a+b,0)||1;
      return (d.v[simDetailSortCol]||0)/tot;
    }
    if(simDetailSortCol==='status'){
      const st=getSimDistStatus(name,d,simDetailParty);
      return {safe:0,lean:1,battleground:2,tossup:3,absent:4}[st]||5;
    }
    return name;
  };
  const distEntries=Object.entries(selRegion?Object.fromEntries(Object.entries(D).filter(([,d])=>d.r===selRegion)):D)
    .sort((a,b)=>{
      const va=sortEntry(a), vb=sortEntry(b);
      return typeof va==='string'?va.localeCompare(vb)*simDetailSortDir:(va-vb)*simDetailSortDir;
    });

  const sdTh=(col,label)=>`<div style="font-size:10px;font-weight:700;color:${focusParties.includes(col)?pc(col):'var(--text3)'};text-transform:uppercase;letter-spacing:.07em;cursor:pointer;user-select:none" onclick="simDetailSortCol='${col}';simDetailSortDir=simDetailSortCol==='${col}'?-simDetailSortDir:1;renderSimulationDetails()">${label}${simDetailSortCol===col?(simDetailSortDir>0?' ▲':' ▼'):' ↕'}</div>`;
  const rows=distEntries.map(([name,d])=>{
    const tot=Object.values(d.v).reduce((a,b)=>a+b,0)||1;
    const allWinners=rankBySeats(d.v,d.s);
    const to=((TO_MAP[name]||{}).to21||0.45)*100;
    const simD=simResults&&simResults[name];
    const simWinner=simD?(simD.seats?.[0]||d.w21):d.w21;
    const status=getSimDistStatus(name,d,simDetailParty);
    const focusCols=focusParties.map(p=>{
      const v=d.v[p]||0;
      const pct=(v/tot*100).toFixed(1);
      const simSeats=simD&&simD.meanSeats?Math.round(simD.meanSeats[p]||0):allWinners.filter(w=>w===p).length;
      const winProb=simD&&simD.meanSeats?Math.min(1,simD.meanSeats[p]||0):(allWinners.includes(p)?0.9:0);
      const projVotes=simD&&simD.adj?Math.round(simD.adj[p]||0):v;
      return `<div style="text-align:center;padding:0 2px">
        <div style="font-size:11px;font-weight:700;color:${pc(p)}">${pct}%</div>
        <div style="font-size:10px;color:${simSeats>0?pc(p):'var(--text4)'}">${simSeats>0?simSeats+'s':'—'}</div>
        <div style="font-size:9px;color:var(--text3)">${projVotes.toLocaleString()}</div>
        <div style="font-size:9px;color:var(--text3)">${Math.round(winProb*100)}%</div>
      </div>`;
    }).join('');
    const otherWinners=[...new Set((simD?simD.seats:allWinners).filter(p=>!focusParties.includes(p)))];
    const otherChips=otherWinners.map(p=>`<span onclick="event.stopPropagation();simDetailParty='${p}';renderSimulationDetails()" style="display:inline-flex;align-items:center;padding:2px 7px;border-radius:4px;font-size:10px;font-weight:700;cursor:pointer;background:${pc(p)}18;color:${pc(p)};border:1px solid ${pc(p)}30;margin:1px">${p}</span>`).join('');
    return `<div onclick="openSimDistModal('${name.replace(/'/g,"\\'")}')" style="display:grid;grid-template-columns:180px 40px 32px 100px 100px 100px 1fr 80px;align-items:center;padding:7px 10px;border-bottom:1px solid var(--border);cursor:pointer;transition:background .1s" onmouseenter="this.style.background='var(--surface2)'" onmouseleave="this.style.background='transparent'">
      <div style="min-width:0">
        <div style="font-size:12px;font-weight:700;color:var(--navy);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${name}</div>
        <div style="font-size:10px;color:var(--text3)">${d.r.replace('Tanger - Tétouan - Al Hoceima','TTH').replace('Casablanca - Settat','Casa').replace('Rabat - Salé - Kénitra','R-S-K').replace(' - Khénifra','').slice(0,24)}</div>
      </div>
      <div style="text-align:center;font-size:11px;font-weight:700;color:var(--text3)">${d.s}</div>
      <div style="text-align:center;font-size:10px;color:var(--text3)">${to.toFixed(0)}%</div>
      ${focusCols}
      <div style="display:flex;gap:2px;flex-wrap:wrap">${otherChips}</div>
      <div style="text-align:right"><span class="pill ${simDistPillClass(status)}">${simDistLabel(status)}</span></div>
    </div>`;
  }).join('');

  const isCustomSim=simResults&&!simResults._baseline;
  // Override summary
  const overridedDists=Object.keys(distSwings).filter(k=>Object.values(distSwings[k]||{}).some(v=>v!==0));
  const guaranteedDists=Object.keys(guaranteedSeats).filter(k=>Object.keys(guaranteedSeats[k]||{}).length>0);
  const overrideBanner=(overridedDists.length||guaranteedDists.length)?`<div style="background:var(--teal-bg);border:1px solid var(--teal);border-radius:7px;padding:8px 12px;margin-bottom:10px;display:flex;align-items:center;gap:8px;flex-wrap:wrap">
    <span style="font-size:11px;font-weight:700;color:var(--teal)">⚙ Overrides actifs</span>
    ${overridedDists.slice(0,6).map(n=>{const sw=distSwings[n]||{};return`<span style="font-size:10px;background:var(--teal);color:#fff;padding:2px 7px;border-radius:10px">${n.split(' ')[0]}:${Object.entries(sw).filter(([,v])=>v!==0).map(([p,v])=>p+(v>=0?'+':'')+v+'pp').join(' ')}</span>`;}).join('')}
    ${guaranteedDists.slice(0,4).map(n=>{const g=guaranteedSeats[n]||{};return`<span style="font-size:10px;background:#6366f1;color:#fff;padding:2px 7px;border-radius:10px">🔒${n.split(' ')[0]}:${Object.entries(g).filter(([,v])=>v>0).map(([p,v])=>p+'×'+v).join(' ')}</span>`;}).join('')}
    <button onclick="setTopTab('buildsim')" style="margin-left:auto;font-size:11px;padding:3px 10px;border:1px solid var(--teal);background:transparent;color:var(--teal);border-radius:4px;cursor:pointer;font-family:Inter,sans-serif">Modifier →</button>
  </div>`:'';
  const html=`
  ${overrideBanner}
  <div class="card" style="margin-bottom:12px;padding:14px 16px">
    <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px">
      <div class="card-title" style="margin:0">${Object.keys(distEntries.reduce((a,[,d])=>(a[d.r]=1,a),{})).length > 1 ? `${distEntries.length} Circonscriptions` : selRegion} — ${isCustomSim?'Votre Simulation':'Prévision Baseline (10k runs)'}</div>
      <div style="font-size:11px;color:var(--text3)">%/sièges/voix/win% · Cliquer pour explorer</div>
    </div>
    ${partySel}
  </div>
  <div class="card" style="padding:0;overflow:hidden">
    <div style="display:grid;grid-template-columns:180px 40px 32px 100px 100px 100px 1fr 80px;align-items:center;padding:8px 10px;background:var(--surface2);border-bottom:2px solid var(--border);position:sticky;top:0;z-index:2">
      ${sdTh('name','Circonscription')}
      ${sdTh('seats','S')}
      ${sdTh('to','TO')}
      ${focusParties.map(p=>sdTh(p,p)).join('')}
      <div style="font-size:10px;font-weight:700;color:var(--text3)">Autres</div>
      ${sdTh('status','Statut')}
    </div>
    ${rows}
  </div>
  <div id="sim-dist-modal" onclick="if(event.target===this)closeSimDistModal()" style="display:none;position:fixed;inset:0;z-index:9000;background:rgba(0,0,0,.45);align-items:center;justify-content:center">
    <div id="sim-dist-modal-body" style="background:var(--surface);border-radius:12px;width:600px;max-height:88vh;overflow-y:auto;box-shadow:0 20px 60px rgba(0,0,0,.3)"></div>
  </div>`;
  document.getElementById('view-content').innerHTML=html;
  renderRightPanel();
}

function openSimDistModal(distName){
  const d=D[distName];if(!d)return;
  const modal=document.getElementById('sim-dist-modal');if(!modal)return;
  const tot=Object.values(d.v).reduce((a,b)=>a+b,0)||1;
  const sorted=Object.entries(d.v).sort((a,b)=>b[1]-a[1]);
  const allWinners2021=rankBySeats(d.v,d.s);
  const uniqueWinners2021=[...new Set(allWinners2021)];
  const simD=simResults&&simResults[distName];
  const simSeatsArr=simD?simD.seats||[]:allWinners2021;
  const simUniqueWinners=[...new Set(simSeatsArr)];
  const simWinner=simSeatsArr[0]||d.w21;
  const winner=uniqueWinners2021[0];
  const closeLosers=sorted.slice(d.s,d.s+2).map(([p])=>p).filter(Boolean);
  const allRanked=sorted.map(([p,v],i)=>({p,v,pct:v/tot*100,rank:i+1}));
  const adv=buildDistAdvantage(distName,d,winner,closeLosers);
  const to=TO_MAP[distName]||{};
  const to21=((to.to21||0.45)*100).toFixed(1);
  const fp=simDetailParty;
  const fpVotes=d.v[fp]||0;
  const fpPct=(fpVotes/tot*100).toFixed(1);
  const fpRank=sorted.findIndex(([p])=>p===fp)+1;
  const fpWins=allWinners2021.filter(w=>w===fp).length;
  const fpChance=simD&&simD.meanSeats?Math.min(1,simD.meanSeats[fp]||0):fpWins?0.9:0;
  const fpStatus=getSimDistStatus(distName,d,fp);

  const bodyHtml=`
  <div style="padding:20px 24px">
    <div style="display:flex;align-items:flex-start;justify-content:space-between;margin-bottom:16px">
      <div>
        <div style="font-size:18px;font-weight:800;color:var(--navy)">${distName}</div>
        <div style="font-size:11px;color:var(--text3);margin-top:2px">${d.r} · ${d.s} seats · ${d.u?'Urban':'Rural'} · TO ${to21}%</div>
      </div>
      <button onclick="closeSimDistModal()" style="font-size:20px;color:var(--text3);background:none;border:none;cursor:pointer;padding:0 0 0 12px;line-height:1">×</button>
    </div>
    <div style="background:${pc(winner)}12;border:2px solid ${pc(winner)}40;border-radius:8px;padding:12px 16px;margin-bottom:12px">
      <div style="display:flex;align-items:center;justify-content:space-between">
        <div>
          <div style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.08em;color:var(--text3);margin-bottom:3px">2021 Rank-1</div>
          <div style="font-size:22px;font-weight:900;color:${pc(winner)}">${winner}</div>
          <div style="font-size:12px;color:var(--text2);margin-top:2px">${((d.v[winner]||0)/tot*100).toFixed(1)}% · ${(d.v[winner]||0).toLocaleString()} votes</div>
        </div>
        <div style="text-align:right">
          <div style="font-size:10px;color:var(--text3);margin-bottom:2px">${simD&&!simResults._baseline?'Sim':'Forecast'} 2026</div>
          <div style="font-size:20px;font-weight:800;color:${pc(simWinner)}">${simWinner}</div>
        </div>
      </div>
    </div>
    <div style="background:${pc(fp)}10;border:2px solid ${pc(fp)}40;border-radius:8px;padding:12px 16px;margin-bottom:12px">
      <div style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.08em;color:${pc(fp)};margin-bottom:6px">${fp} — selected party</div>
      <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:8px">
        <div style="text-align:center"><div style="font-size:18px;font-weight:800;color:${pc(fp)}">${fpPct}%</div><div style="font-size:10px;color:var(--text3)">Vote share</div></div>
        <div style="text-align:center"><div style="font-size:18px;font-weight:800;color:var(--navy)">#${fpRank}</div><div style="font-size:10px;color:var(--text3)">Rank</div></div>
        <div style="text-align:center"><div style="font-size:18px;font-weight:800;color:${fpWins>0?'var(--green)':'var(--red)'}">${fpWins}s</div><div style="font-size:10px;color:var(--text3)">2021 seats</div></div>
        <div style="text-align:center"><div style="font-size:18px;font-weight:800;color:${fpChance>=0.6?'var(--green)':fpChance>=0.35?'var(--amber)':'var(--red)'}">${(fpChance*100).toFixed(0)}%</div><div style="font-size:10px;color:var(--text3)">Win prob</div></div>
      </div>
      <div style="margin-top:8px;padding-top:8px;border-top:1px solid ${pc(fp)}30">
        <span class="pill ${simDistPillClass(fpStatus)}">${simDistLabel(fpStatus)}</span>
        ${fpWins===0&&fpRank<=d.s+1?`<span style="font-size:11px;color:var(--amber);margin-left:8px">First loser — within striking distance</span>`:''}
        ${fpWins>0&&fpChance<0.5?`<span style="font-size:11px;color:var(--red);margin-left:8px">Seat at risk in simulation</span>`:''}
        ${fpWins>0&&fpChance>=0.85?`<span style="font-size:11px;color:var(--green);margin-left:8px">Seat appears secure</span>`:''}
      </div>
    </div>
    <div style="margin-bottom:12px">
      <div style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.08em;color:var(--text3);margin-bottom:7px">Seat allocation (${simD&&!simResults._baseline?'simulation':'2021 baseline'})</div>
      <div style="display:flex;gap:6px;flex-wrap:wrap">
        ${(simD&&!simResults._baseline?simUniqueWinners:uniqueWinners2021).map(p=>{
          const s=(simD&&!simResults._baseline?simSeatsArr:allWinners2021).filter(w=>w===p).length;
          return `<div style="padding:8px 13px;border-radius:7px;background:${pc(p)}15;border:2px solid ${p===fp?pc(p):pc(p)+'40'}">
            <div style="font-size:13px;font-weight:900;color:${pc(p)}">${p}</div>
            <div style="font-size:12px;font-weight:700;color:var(--navy)">${s}s</div>
            <div style="font-size:10px;color:var(--text3)">${((d.v[p]||0)/tot*100).toFixed(1)}%</div>
          </div>`;
        }).join('')}
      </div>
    </div>
    <div style="margin-bottom:12px">
      <div style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.08em;color:var(--text3);margin-bottom:7px">Full vote ranking</div>
      ${allRanked.slice(0,Math.min(allRanked.length,9)).map((r,i)=>{
        const isSeat=i<d.s;
        const isCutoff=i===d.s;
        const barW=(r.v/sorted[0][1]*100).toFixed(0);
        const isFocus=r.p===fp;
        return `${isCutoff?`<div style="display:flex;align-items:center;gap:6px;margin:4px 0;font-size:10px;color:var(--red);font-weight:700"><div style="flex:1;height:1px;background:var(--red)"></div>CUTOFF<div style="flex:1;height:1px;background:var(--red)"></div></div>`:''}
        <div style="display:flex;align-items:center;gap:8px;padding:4px ${isFocus?'4':'0'}px;${isSeat?'':'opacity:.7'}${isFocus?';background:'+pc(fp)+'0a;border-radius:4px':''};border-bottom:1px solid var(--border)">
          <span style="font-size:10px;color:var(--text3);min-width:14px">${r.rank}</span>
          <div style="width:8px;height:8px;border-radius:2px;background:${pc(r.p)};flex-shrink:0"></div>
          <span style="font-size:12px;font-weight:${isSeat||isFocus?'700':'400'};color:${pc(r.p)};min-width:36px">${r.p}${isFocus?' ◀':''}</span>
          <div style="flex:1;height:5px;background:var(--border);border-radius:3px"><div style="height:100%;width:${barW}%;background:${pc(r.p)};border-radius:3px"></div></div>
          <span style="font-size:11px;min-width:36px;text-align:right">${r.pct.toFixed(1)}%</span>
          <span style="font-size:10px;color:var(--text3);min-width:58px;text-align:right">${r.v.toLocaleString()}</span>
          ${isSeat?`<span style="font-size:10px;color:var(--green);font-weight:700;min-width:40px">✓ SEAT</span>`:`<span style="min-width:40px"></span>`}
        </div>`;
      }).join('')}
    </div>
    <div style="background:var(--navy);color:#fff;border-radius:8px;padding:16px;margin-bottom:12px">
      <div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.08em;color:#a8d4e8;margin-bottom:10px">Why ${winner} won — and how</div>
      <div style="display:flex;flex-direction:column;gap:7px;font-size:12px;line-height:1.65">
        <div><span style="color:${pc(winner)};font-weight:700">◆ Vote lead: </span>${adv.leadText}</div>
        <div><span style="color:#a8d4e8;font-weight:700">◆ History: </span>${adv.histText}</div>
        <div><span style="color:#a8d4e8;font-weight:700">◆ Territory: </span>${adv.geoText}</div>
        ${adv.commText?`<div><span style="color:#a8d4e8;font-weight:700">◆ Communes: </span>${adv.commText}</div>`:''}
        <div><span style="color:#a8d4e8;font-weight:700">◆ Turnout: </span>${adv.toText}</div>
      </div>
    </div>
    <div>
      <div style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.08em;color:var(--text3);margin-bottom:7px">Winner trajectory 2011 → 2026</div>
      <div style="display:flex;gap:6px;align-items:center;flex-wrap:wrap">
        ${['11','15','16','21'].map(yr=>{const w=d['w'+yr];return w?`<div style="text-align:center"><div style="font-size:9px;color:var(--text3);margin-bottom:3px">20${yr}</div><div style="width:36px;height:36px;border-radius:6px;background:${pc(w)}18;border:1px solid ${pc(w)}40;display:flex;align-items:center;justify-content:center;font-size:10px;font-weight:800;color:${pc(w)}">${w}</div></div>`:'';}).filter(Boolean).join('<span style="color:var(--border2);font-size:16px;margin-top:10px">→</span>')}
        <span style="color:var(--border2);font-size:16px;margin-top:10px">→</span>
        <div style="text-align:center">
          <div style="font-size:9px;color:var(--teal);margin-bottom:3px;font-weight:700">2026↗</div>
          <div style="width:36px;height:36px;border-radius:6px;background:${pc(simWinner)}22;border:2px solid ${pc(simWinner)};display:flex;align-items:center;justify-content:center;font-size:10px;font-weight:800;color:${pc(simWinner)}">${simWinner}</div>
        </div>
      </div>
    </div>
  </div>`;

  document.getElementById('sim-dist-modal-body').innerHTML=bodyHtml;
  modal.style.display='flex';
}

