function addIntelGlobal(){
  const dist=document.getElementById('intel-dist')?.value.trim();
  const cat=document.getElementById('intel-cat')?.value||'ground';
  const text=document.getElementById('intel-text')?.value.trim();
  if(!text)return;
  intelLog.push({dist:dist||'National',cat,text,time:new Date().toLocaleTimeString(),id:Date.now()});
  document.getElementById('intel-dist').value='';document.getElementById('intel-text').value='';
  document.getElementById('intel-cnt').textContent=intelLog.length;
  renderIntelView();
}

function aiIntel(){
  const base=calcBase();
  const sim=simResults?Object.fromEntries(MAJOR.map(p=>[p,simResults._national[p]||0])):base;
  const seats=MAJOR.map(p=>`${p}:${sim[p]||0}`).join(', ');
  const intel=intelLog.length?intelLog.map(e=>`[${e.cat}-${e.dist||'National'}]: ${e.text}`).join('\n'):'No intel.';
  const toss=Object.entries(D).filter(([,d])=>d.m<3).map(([n,d])=>`${n}(${d.s}s,${d.w21}+${d.m}pp)`).join('; ');
  const prompt=`POLINTEL Morocco 2026.\nSeats (305 total, maj=153): ${seats}\nToss-ups: ${toss||'none'}\nIntel:\n${intel}\n\nProvide: 1) Strategic implications, 2) Districts to reprioritize, 3) Coalition scenarios, 4) Key recommendations.`;
  if(window.sendPrompt)sendPrompt(prompt);
  else{const ta=document.createElement('textarea');ta.value=prompt;document.body.appendChild(ta);ta.select();document.execCommand('copy');document.body.removeChild(ta);alert('Analysis prompt copied!');}
}

function renderJSAPview(){
  document.getElementById('view-tabs').innerHTML='';
  const sapArr=Object.entries(D).map(([n,d])=>({n,...d,sap:getJSAPscore(d,n),to21:(TO_MAP[n]||{}).to21||0.45})).sort((a,b)=>b.sap-a.sap);

  // For each district, compute at jsapForce what seat JSAP would take and from whom
  const computeJSAPSeatImpact=(name,d,force)=>{
    if(!force||force===0)return null;
    const to=TO_MAP[name]||{};
    const voixAdd=to.voixAdd||0;
    const jsapScore=getJSAPscore(d,name);
    const jsapVotes=voixAdd*force/100*jsapScore;
    if(!jsapVotes)return null;
    const tot=Object.values(d.v).reduce((a,b)=>a+b,0)||1;
    // Sort parties by votes
    const ranked=Object.entries(d.v).sort((a,b)=>b[1]-a[1]);
    // Add JSAP and re-rank
    const withJSAP=[...ranked,['JSAP',jsapVotes]].sort((a,b)=>b[1]-a[1]);
    // Current winners without JSAP (Hare/largest remainder approximation)
    const baseWinners=ranked.slice(0,d.s).map(([p])=>p);
    // Winners with JSAP
    const newWinners=withJSAP.slice(0,d.s).map(([p])=>p);
    // Who loses a seat?
    const baseCounts={}; baseWinners.forEach(p=>baseCounts[p]=(baseCounts[p]||0)+1);
    const newCounts={}; newWinners.forEach(p=>newCounts[p]=(newCounts[p]||0)+1);
    const loser=Object.entries(baseCounts).find(([p,n])=>(newCounts[p]||0)<n)?.[0];
    const jsapWins=newWinners.includes('JSAP');
    const lastSeatP=ranked[d.s-1]?.[0];
    const firstLoserP=ranked[d.s]?.[0];
    const gap=ranked[d.s-1]&&ranked[d.s]?((ranked[d.s-1][1]-ranked[d.s][1])/tot*100).toFixed(1):'?';
    return {jsapVotes:Math.round(jsapVotes),jsapWins,loser,lastSeatP,firstLoserP,gap,baseWinners,newWinners};
  };

  const html=`
  <div class="sap-card">
    <div class="sap-title">⚡ JSAP — Jeunes Sans Appartenance Politique</div>
    <div class="sap-desc">Le modèle JSAP représente des campagnes indépendantes portées par des jeunes qui mobilisent les non-votants urbains. Il cible les circonscriptions à faible participation législative, forte concentration jeune, et faible loyauté partisane — captant l'électorat non-votant qu'aucun parti traditionnel n'atteint.</div>
    <div class="slider-row">
      <span class="slider-label">Force</span>
      <input type="range" min="0" max="20" step="1" value="${jsapForce}" id="jsap-force-slider" oninput="jsapForce=parseInt(this.value);document.getElementById('jsap-force-v').textContent=this.value+'%';renderJSAPview()">
      <span class="slider-val" id="jsap-force-v">${jsapForce}%</span>
    </div>
    <div style="font-size:11px;color:var(--text2)">% de non-votants mobilisables captés par le mouvement JSAP</div>
  </div>
  <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px">
    <div class="card">
      <div class="card-title">Top districts fertiles JSAP</div>
      ${sapArr.slice(0,15).map((d,i)=>{
        const to=(TO_MAP[d.n]||{});
        const voixAdd=to.voixAdd||0;
        const jsapVotes=Math.round(voixAdd*(jsapForce/100));
        const ranked=Object.entries(d.v||{}).sort((a,b)=>b[1]-a[1]);
        const lastWinner=ranked[d.s-1];
        const firstLoser=ranked[d.s];
        const tot=Object.values(d.v||{}).reduce((a,b)=>a+b,0)||1;
        const lastGap=lastWinner&&firstLoser?((lastWinner[1]-firstLoser[1])/tot*100).toFixed(1):'?';
        const impact=jsapForce>0?computeJSAPSeatImpact(d.n,d,jsapForce):null;
        return `<div style="border-bottom:1px solid var(--border);padding:8px 0" id="jsap-row-${i}">
          <div style="display:flex;align-items:center;justify-content:space-between;cursor:pointer" onclick="toggleJSAPDetail('jsap-detail-${i}')">
            <div>
              <div style="font-size:12px;font-weight:600;color:var(--navy)">${d.n}</div>
              <div style="font-size:10px;color:var(--text3);margin-top:1px">Jeunes ${d.yth||14}% · TO ${(d.to21*100).toFixed(0)}% · ${d.u?'Urbain':'Rural'}</div>
            </div>
            <div style="display:flex;gap:6px;align-items:center">
              <div class="pill" style="background:#f0fdfa;color:#0891b2">${(d.sap*100).toFixed(0)}%</div>
              ${impact&&impact.jsapWins&&impact.loser?`<div class="pill" style="background:#fee2e2;color:#dc2626;font-size:9px">−${impact.loser}</div>`:''}
              <span style="font-size:10px;color:var(--text3)">▼</span>
            </div>
          </div>
          <div id="jsap-detail-${i}" style="display:none;margin-top:8px;padding:10px 12px;background:#f0fdfa;border-radius:6px;font-size:11px">
            <div style="font-weight:700;color:#0891b2;margin-bottom:8px">Pourquoi fertile pour JSAP</div>
            <div style="display:grid;grid-template-columns:1fr 1fr;gap:4px;margin-bottom:8px">
              <div>🗳️ TO 2021: <strong>${(d.to21*100).toFixed(0)}%</strong> ${d.to21<0.35?'⚡ Très bas':d.to21<0.45?'↓ Bas':''}</div>
              <div>👥 Jeunes: <strong>${d.yth||14}%</strong> ${(d.yth||14)>18?'⚡ Élevé':''}</div>
              <div>🏙️ Type: <strong>${d.u?'Urbain':'Rural'}</strong></div>
              <div>💪 Mobilisable: <strong>~${voixAdd.toLocaleString()}</strong> voix</div>
              <div>📊 Écart dernier siège: <strong>${lastGap}pp</strong></div>
              <div>🎯 JSAP à ${jsapForce}%: <strong>+${jsapVotes.toLocaleString()} voix</strong></div>
            </div>
            ${impact?`
            <div style="background:#fff;border-radius:5px;padding:8px;border:1px solid #99f6e4;margin-top:4px">
              <div style="font-size:10px;font-weight:700;color:#0891b2;margin-bottom:4px">IMPACT PROJETÉ À ${jsapForce}%</div>
              ${impact.jsapWins?`
                <div style="font-size:11px;color:#059669;font-weight:600;margin-bottom:4px">✓ JSAP obtient un siège</div>
                ${impact.loser?`<div style="font-size:11px;color:#dc2626"><strong>${impact.loser}</strong> perd son siège au profit de JSAP</div>
                <div style="font-size:10px;color:var(--text3);margin-top:3px">Base: ${impact.baseWinners.join(', ')} → Avec JSAP: ${impact.newWinners.join(', ')}</div>`:
                '<div style="font-size:11px;color:var(--text3)">Repartition des sièges inchangée malgré la présence JSAP</div>'}
              `:
              `<div style="font-size:11px;color:var(--amber)">JSAP (${impact.jsapVotes.toLocaleString()} voix) trop faible pour décrocher un siège<br>
              Écart vs ${impact.lastSeatP}: ${lastGap}pp — il faut plus de force</div>`}
            </div>`:''}
            <div style="margin-top:6px"><a href="#" onclick="event.preventDefault();selectDist('${d.n.replace(/'/g,"\\'")}')" style="color:#0891b2;font-weight:600">Voir profil complet →</a></div>
          </div>
        </div>`;}).join('')}
    </div>
    <div class="card">
      <div class="card-title">Modèle JSAP — paramètres</div>
      <p style="font-size:12px;color:var(--text2);line-height:1.7;margin-bottom:12px">
        Le modèle évalue chaque circonscription sur trois dimensions: <strong>faible participation législative</strong> (districts urbains TO &lt;35%), <strong>concentration jeune</strong> (20–24 ans &gt;18% des inscrits), et <strong>densité urbaine</strong> (mobilisation réseau rapide).
      </p>
      <div class="score-bar"><span class="score-label">Poids participation</span><div class="score-track"><div class="score-fill" style="width:40%;background:var(--teal)"></div></div><span class="score-val">40%</span></div>
      <div class="score-bar"><span class="score-label">Poids jeunesse</span><div class="score-track"><div class="score-fill" style="width:35%;background:#0891b2"></div></div><span class="score-val">35%</span></div>
      <div class="score-bar"><span class="score-label">Poids urbain</span><div class="score-track"><div class="score-fill" style="width:25%;background:#0891b2"></div></div><span class="score-val">25%</span></div>
      <div class="divider"></div>
      ${jsapForce>0?(()=>{
        const impacts=sapArr.slice(0,20).map(d=>{
          const imp=computeJSAPSeatImpact(d.n,d,jsapForce);
          return imp&&imp.jsapWins?{name:d.n,loser:imp.loser,votes:imp.jsapVotes}:null;
        }).filter(Boolean);
        return impacts.length?`
        <div style="font-size:10px;font-weight:700;color:var(--text3);text-transform:uppercase;letter-spacing:.08em;margin-bottom:6px">Sièges pris à qui (top 20 districts)</div>
        ${impacts.map(imp=>`<div style="display:flex;align-items:center;gap:6px;padding:4px 0;border-bottom:1px solid var(--border);font-size:11px">
          <div style="flex:1;color:var(--navy);font-weight:500">${imp.name}</div>
          ${imp.loser?`<span style="color:#dc2626;font-weight:700">−${imp.loser}</span>
          <span style="color:#0891b2;font-weight:700">+JSAP</span>`:'<span style="color:var(--text3)">redistribution interne</span>'}
        </div>`).join('')}
        <div style="font-size:11px;color:var(--teal);font-weight:700;margin-top:8px">Total JSAP: ~${impacts.length} siège(s) possible(s)</div>`:
        `<div style="font-size:11px;color:var(--text3)">À ${jsapForce}% de force, JSAP ne prend aucun siège dans le top 20 — augmentez la force.</div>`;
      })():`<div style="font-size:11px;color:var(--text2)">Bougez le curseur de force pour voir l'impact sur les sièges.</div>`}
      ${jsapForce>0?`<div class="alert al-teal" style="margin-top:8px"><span class="al-icon"></span><span>JSAP à ${jsapForce}% actif — districts urbains avec jeunes &gt;20% verront une perturbation significative.</span></div>`:''}
    </div>
  </div>`;
  document.getElementById('view-content').innerHTML=html;
}

