async function loadNewsFeeds(force=false){
  if(newsState.loading) return;
  if(newsState.loaded && !force) return;
  newsState.loading = true;
  newsState.articles = [];
  const btn = document.getElementById('news-refresh-btn');
  const status = document.getElementById('news-status');
  const list = document.getElementById('news-list');
  if(btn) btn.textContent = '⏳ Loading…';
  if(list) list.innerHTML = `<div style="text-align:center;padding:30px;color:var(--text3)"><div style="width:32px;height:32px;border:2px solid var(--border);border-top-color:var(--teal);border-radius:50%;margin:0 auto 10px;animation:spin 1s linear infinite"></div><div style="font-size:11px">Fetching from ${MOROCCAN_SOURCES.length} sources…</div></div>`;

  // Use a public RSS-to-JSON proxy (rss2json.com)
  const PROXY = 'https://api.rss2json.com/v1/api.json?rss_url=';
  let loaded = 0; let failed = 0;

  // Load in parallel batches of 10
  const batchSize = 10;
  for(let i=0; i<MOROCCAN_SOURCES.length; i+=batchSize){
    const batch = MOROCCAN_SOURCES.slice(i, i+batchSize);
    const promises = batch.map(async src => {
      try{
        const res = await fetch(PROXY + encodeURIComponent(src.rss), {signal: AbortSignal.timeout(8000)});
        const data = await res.json();
        if(data.status === 'ok' && data.items?.length){
          const articles = data.items.slice(0,8).map(item => ({
            title: item.title||'',
            link: item.link||src.url,
            pubDate: item.pubDate ? new Date(item.pubDate) : new Date(),
            description: (item.description||'').replace(/<[^>]+>/g,'').slice(0,200),
            source: src.n,
            sourceCat: src.cat,
            sourceLang: src.lang,
            sourceUrl: src.url,
            political: isPolitical(item.title + ' ' + (item.description||'')),
          }));
          newsState.articles.push(...articles);
          loaded++;
        } else { failed++; }
      } catch { failed++; }
    });
    await Promise.allSettled(promises);
    if(status) status.textContent = `Loaded ${loaded} sources, ${failed} unavailable… (${newsState.articles.length} articles)`;
  }

  // Sort by date
  newsState.articles.sort((a,b) => b.pubDate - a.pubDate);
  newsState.loaded = true;
  newsState.loading = false;
  if(btn) btn.textContent = '🔄 Refresh';
  if(status) status.textContent = `✓ ${newsState.articles.length} articles from ${loaded} sources · ${failed} sources unavailable · Updated ${new Date().toLocaleTimeString()}`;
  newsFilter();
}

function isPolitical(text){
  const t = text.toLowerCase();
  return POLITICAL_KEYWORDS.some(k => t.includes(k)) || POLITICAL_KEYWORDS_AR.some(k => text.includes(k));
}

function newsFilter(){
  const search = (document.getElementById('news-search')?.value||'').toLowerCase();
  const cat = document.getElementById('news-cat')?.value || 'Tous';
  const lang = document.getElementById('news-lang')?.value || 'all';
  const polOnly = document.getElementById('news-political')?.checked || false;
  const src = newsState.selectedSource;

  let filtered = newsState.articles.filter(a => {
    if(search && !a.title.toLowerCase().includes(search) && !a.description.toLowerCase().includes(search) && !a.source.toLowerCase().includes(search)) return false;
    if(cat !== 'Tous' && a.sourceCat !== cat) return false;
    if(lang !== 'all' && a.sourceLang !== lang) return false;
    if(polOnly && !a.political) return false;
    if(src && a.source !== src) return false;
    return true;
  });

  newsState.filtered = filtered;
  renderNewsArticles(filtered);
}

function renderNewsArticles(articles){
  const list = document.getElementById('news-list');
  if(!list) return;
  if(!articles.length){
    list.innerHTML = `<div style="text-align:center;padding:30px;color:var(--text3)"><div style="font-size:13px">No articles match your filters</div><div style="font-size:11px;margin-top:4px">${newsState.loaded ? 'Try adjusting your search or filters' : 'Load news first'}</div>${newsState.selectedSource?`<button onclick="newsState.selectedSource=null;newsFilter()" style="margin-top:10px;font-size:11px;padding:4px 12px;border:1px solid var(--border);border-radius:5px;cursor:pointer;font-family:Inter,sans-serif;background:#fff">Clear source filter</button>`:''}</div>`;
    return;
  }

  list.innerHTML = articles.slice(0,80).map(a => {
    const age = getAge(a.pubDate);
    const polBadge = a.political ? `<span style="font-size:9px;padding:1px 6px;background:var(--teal-bg);color:var(--teal2);border-radius:3px;font-weight:600">POLITIQUE</span>` : '';
    return `<div class="card" style="padding:10px 14px;cursor:pointer;transition:border-color .12s" onmouseenter="this.style.borderColor='var(--teal)'" onmouseleave="this.style.borderColor='var(--border)'" onclick="window.open('${a.link.replace(/'/g,"\\'")}','_blank')">
      <div style="display:flex;align-items:flex-start;gap:8px">
        <div style="flex:1;min-width:0">
          <div style="display:flex;align-items:center;gap:5px;margin-bottom:4px;flex-wrap:wrap">
            <span style="font-size:10px;font-weight:700;color:${a.sourceLang==='ar'?'var(--teal)':'var(--navy)'}">${a.source}</span>
            <span style="font-size:9px;color:var(--text3);background:var(--surface2);padding:1px 5px;border-radius:3px">${a.sourceCat}</span>
            ${polBadge}
            <span style="font-size:9px;color:var(--text3);margin-left:auto">${age}</span>
          </div>
          <div style="font-size:12px;font-weight:600;color:var(--navy);line-height:1.4;margin-bottom:4px">${escHtml(a.title)}</div>
          ${a.description ? `<div style="font-size:11px;color:var(--text3);line-height:1.5;overflow:hidden;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical">${escHtml(a.description)}</div>` : ''}
        </div>
      </div>
    </div>`;
  }).join('');
}

function getAge(date){
  const diff = Date.now() - date.getTime();
  const mins = Math.floor(diff/60000);
  if(mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins/60);
  if(hrs < 24) return `${hrs}h ago`;
  return `${Math.floor(hrs/24)}d ago`;
}

async function runNewsAnalysis(){
  if(newsState.aiLoading) return;
  if(!newsState.articles.length){ document.getElementById('news-ai-output').textContent = 'Load news first.'; return; }

  newsState.aiLoading = true;
  const btn = document.getElementById('news-ai-btn');
  const out = document.getElementById('news-ai-output');
  if(btn){ btn.disabled=true; btn.textContent='Generating…'; }
  if(out) out.innerHTML = `<div style="display:flex;align-items:center;gap:8px;color:var(--text3)"><div style="width:16px;height:16px;border:2px solid var(--border);border-top-color:var(--teal);border-radius:50%;animation:spin 1s linear infinite"></div>Analysing ${newsState.articles.filter(a=>a.political).length} political articles…</div>`;

  // Build a digest of the top political articles
  const political = newsState.articles.filter(a=>a.political).slice(0,30);
  const digest = political.map((a,i) => `${i+1}. [${a.source}] ${a.title}${a.description?' — '+a.description:''}`).join('\n');

  const prompt = `You are intelX, an AI political intelligence system specialising in Morocco.

Today's political news digest from Moroccan media (${new Date().toLocaleDateString('fr-MA')}):

${digest}

Based on these headlines and articles, provide a concise political intelligence briefing covering:

1. **KEY POLITICAL DEVELOPMENTS** — What's the most significant political news today?
2. **ELECTORAL RELEVANCE** — Any news directly relevant to the 2026 legislative elections (party positioning, government moves, social issues that could affect vote)?
3. **PARTY SIGNALS** — Any notable statements or moves from RNI, PAM, PI, PJD, USFP, MP, UC or PPS?
4. **PUBLIC MOOD INDICATORS** — What issues are dominating public discourse? Implications for voter sentiment?
5. **WATCH LIST** — 2-3 stories to monitor closely over the next 48 hours

Be concise, analytical, and reference specific sources. Write as a briefing for a senior political strategist.`;

  try {
    const res = await fetch('/api/claude', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': 'Bearer ' + sessionStorage.getItem('intelx_s')
      },
      body: JSON.stringify({ model: 'claude-haiku-4-5-20251001', max_tokens: 1200, messages: [{ role: 'user', content: prompt }] })
    });
    const data = await res.json();
    if(data.error) throw new Error(data.error.message || data.error);
    const text = data.content?.filter(b=>b.type==='text').map(b=>b.text).join('') || '';
    newsState.aiAnalysis = text;
    if(out) out.innerHTML = formatCommsResponse(text);
  } catch(err) {
    if(out) out.innerHTML = `<span style="color:var(--red)">Error: ${escHtml(err.message)}</span>`;
  } finally {
    newsState.aiLoading = false;
    if(btn){ btn.disabled=false; btn.textContent='Refresh briefing'; }
  }
}


// ── ORGA STATUS ──────────────────────────────────────────────────────────────
let orgaData = JSON.parse(localStorage.getItem('intelx_orga') || '{}');

function saveOrga(){ localStorage.setItem('intelx_orga', JSON.stringify(orgaData)); }

function getOrgaVoteAdj(party, distName, communes){
  // District-level adj
  let distAdj = 1.0;
  const ds = orgaData['d:'+distName]?.[party];
  if(ds !== undefined){
    if(ds < 15) distAdj = 0.50;
    else if(ds < 30) distAdj = 0.60;
    else if(ds < 50) distAdj = 0.70;
  }
  // Commune-level: average adj across communes of this district
  let commAdj = 1.0;
  if(communes && communes.length){
    const adjs = communes.map(c => {
      const cs = orgaData['c:'+c.n]?.[party];
      if(cs === undefined) return 1.0;
      if(cs < 15) return 0.50;
      if(cs < 30) return 0.60;
      if(cs < 50) return 0.70;
      return 1.0;
    });
    commAdj = adjs.reduce((a,b)=>a+b,0)/adjs.length;
  }
  return Math.min(distAdj, commAdj);
}

function renderOrgaView(){
  document.getElementById('view-tabs').innerHTML='';
  document.getElementById('rp-head').textContent='Organisational Status';

  const distList = Object.keys(D).sort();
  const selDist2 = window._orgaSelDist || '';

  const html=`
  <div class="card" style="margin-bottom:10px">
    <div class="card-title">Organisational Status Input</div>
    <p style="font-size:12px;color:var(--text2);margin-bottom:10px;line-height:1.6">
      Enter an organisational score (0–100) for a party in a district or commune.
      Scores below 50 reduce that party's votes by 30% in simulation, below 30 by 40%, below 15 by 50%.
    </p>
    <div style="display:flex;gap:8px;flex-wrap:wrap;align-items:flex-end;margin-bottom:10px">
      <div>
        <div style="font-size:10px;font-weight:600;color:var(--text3);margin-bottom:3px;text-transform:uppercase">Level</div>
        <select id="orga-level" onchange="document.getElementById('orga-commune-wrap').style.display=this.value==='commune'?'block':'none'" style="font-size:12px;padding:6px 10px;border-radius:5px;border:1px solid var(--border)">
          <option value="district">District</option>
          <option value="commune">Commune</option>
        </select>
      </div>
      <div>
        <div style="font-size:10px;font-weight:600;color:var(--text3);margin-bottom:3px;text-transform:uppercase">District</div>
        <select id="orga-dist" onchange="window._orgaSelDist=this.value;renderOrgaView()" style="font-size:12px;padding:6px 10px;border-radius:5px;border:1px solid var(--border)">
          <option value="">Choose district…</option>
          ${distList.map(n=>`<option value="${n}" ${selDist2===n?'selected':''}>${n}</option>`).join('')}
        </select>
      </div>
      <div id="orga-commune-wrap" style="display:none">
        <div style="font-size:10px;font-weight:600;color:var(--text3);margin-bottom:3px;text-transform:uppercase">Commune</div>
        <select id="orga-commune" style="font-size:12px;padding:6px 10px;border-radius:5px;border:1px solid var(--border)">
          <option value="">Choose commune…</option>
          ${selDist2&&COMMUNES[selDist2]?COMMUNES[selDist2].map(c=>`<option value="${c.n}">${c.n}</option>`).join(''):''}
        </select>
      </div>
      <div>
        <div style="font-size:10px;font-weight:600;color:var(--text3);margin-bottom:3px;text-transform:uppercase">Party</div>
        <select id="orga-party" style="font-size:12px;padding:6px 10px;border-radius:5px;border:1px solid var(--border)">
          ${MAJOR.map(p=>`<option value="${p}">${p}</option>`).join('')}
        </select>
      </div>
      <div>
        <div style="font-size:10px;font-weight:600;color:var(--text3);margin-bottom:3px;text-transform:uppercase">Score (0–100)</div>
        <input type="number" id="orga-score" min="0" max="100" value="75" style="font-size:12px;padding:6px 10px;border-radius:5px;border:1px solid var(--border);width:80px">
      </div>
      <button onclick="saveOrgaEntry()" class="run-btn" style="height:34px;padding:0 16px;font-size:12px">Save</button>
    </div>
    <div id="orga-msg" style="font-size:11px;color:var(--teal);min-height:16px"></div>
  </div>

  <div class="card">
    <div class="card-title">Saved organisational scores</div>
    ${Object.keys(orgaData).length===0?'<div style="font-size:12px;color:var(--text3)">No scores entered yet.</div>':
      `<table style="width:100%;border-collapse:collapse;font-size:12px">
        <thead><tr style="border-bottom:2px solid var(--border)">
          <th style="text-align:left;padding:6px 8px;color:var(--text3);font-weight:600">Level</th>
          <th style="text-align:left;padding:6px 8px;color:var(--text3);font-weight:600">Location</th>
          <th style="text-align:left;padding:6px 8px;color:var(--text3);font-weight:600">Party</th>
          <th style="text-align:right;padding:6px 8px;color:var(--text3);font-weight:600">Score</th>
          <th style="text-align:right;padding:6px 8px;color:var(--text3);font-weight:600">Vote adj</th>
          <th style="padding:6px 8px"></th>
        </tr></thead>
        <tbody>
        ${Object.entries(orgaData).flatMap(([key,parties])=>
          Object.entries(parties).map(([party,score])=>{
            const isComm=key.startsWith('c:');
            const loc=key.slice(2);
            const adj=score<15?'-50%':score<30?'-40%':score<50?'-30%':'none';
            const adjCol=score<50?'var(--red)':'var(--green)';
            return `<tr style="border-bottom:1px solid var(--border)">
              <td style="padding:6px 8px;color:var(--text3)">${isComm?'Commune':'District'}</td>
              <td style="padding:6px 8px;font-weight:600">${loc}</td>
              <td style="padding:6px 8px"><span style="color:${PC[party]||'#333'};font-weight:700">${party}</span></td>
              <td style="padding:6px 8px;text-align:right;font-weight:700">${score}</td>
              <td style="padding:6px 8px;text-align:right;color:${adjCol};font-weight:600">${adj}</td>
              <td style="padding:6px 8px;text-align:right"><button onclick="deleteOrgaEntry('${key}','${party}')" style="font-size:10px;padding:2px 8px;background:#fdf0f0;color:var(--red);border:1px solid #fecaca;border-radius:4px;cursor:pointer;font-family:Inter,sans-serif">Remove</button></td>
            </tr>`;
          })
        ).join('')}
        </tbody>
      </table>`
    }
    ${Object.keys(orgaData).length>0?`<button onclick="orgaData={};saveOrga();renderOrgaView()" style="margin-top:10px;font-size:11px;padding:4px 12px;background:#fdf0f0;color:var(--red);border:1px solid #fecaca;border-radius:4px;cursor:pointer;font-family:Inter,sans-serif">Clear all</button>`:''}
  </div>`;

  document.getElementById('view-content').innerHTML=html;
}

function saveOrgaEntry(){
  const level=document.getElementById('orga-level').value;
  const dist=document.getElementById('orga-dist').value;
  const commune=document.getElementById('orga-commune').value;
  const party=document.getElementById('orga-party').value;
  const score=parseInt(document.getElementById('orga-score').value);
  const msg=document.getElementById('orga-msg');
  if(!dist){msg.textContent='Please select a district.';return;}
  if(level==='commune'&&!commune){msg.textContent='Please select a commune.';return;}
  if(isNaN(score)||score<0||score>100){msg.textContent='Score must be 0–100.';return;}
  const key=(level==='commune'?'c:'+commune:'d:'+dist);
  if(!orgaData[key])orgaData[key]={};
  orgaData[key][party]=score;
  saveOrga();
  msg.textContent=`✓ Saved: ${party} in ${level==='commune'?commune:dist} = ${score}`;
  setTimeout(()=>{msg.textContent='';},2000);
  renderOrgaView();
}

function deleteOrgaEntry(key,party){
  if(orgaData[key])delete orgaData[key][party];
  if(orgaData[key]&&Object.keys(orgaData[key]).length===0)delete orgaData[key];
  saveOrga();
  renderOrgaView();
}


// ─────────────────────────── BUILD SIMULATION TAB ───────────────────────────
// State: per-district overrides stored in distSwings + guaranteedSeats + distToAdj
// distToAdj = {distName: {natAdj:pp}}

function renderBuildSimView(){
  document.getElementById('view-tabs').innerHTML='';
  const allRegions=[...new Set(Object.values(D).map(d=>d.r))].sort();

  // Header + controls
  const headerHtml=`
  <div class="card" style="margin-bottom:10px">
    <div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap">
      <div style="font-size:15px;font-weight:700;color:var(--navy);flex:1">⚙ Construction de la Simulation 2026</div>
      <button onclick="loadBaselineSim()" style="padding:6px 14px;background:var(--teal);color:#fff;border:none;border-radius:6px;font-size:12px;font-weight:600;cursor:pointer;font-family:Inter,sans-serif">📊 Charger forecast baseline</button>
      <button onclick="resetAllOverrides()" style="padding:6px 14px;background:var(--red-bg);color:var(--red);border:1px solid var(--red);border-radius:6px;font-size:12px;font-weight:600;cursor:pointer;font-family:Inter,sans-serif">🗑 Reset tout</button>
      <button onclick="applyBuildSim()" style="padding:6px 18px;background:var(--navy);color:#fff;border:none;border-radius:6px;font-size:12px;font-weight:700;cursor:pointer;font-family:Inter,sans-serif">▶ Lancer simulation</button>
    </div>
    <div style="display:flex;gap:8px;margin-top:8px;flex-wrap:wrap;align-items:center">
      <input type="text" placeholder="🔍 Rechercher une circonscription…" value="${buildSimSearch}" oninput="buildSimSearch=this.value;renderBuildSimView()" style="flex:1;min-width:180px;height:30px;border:1px solid var(--border);border-radius:5px;padding:0 10px;font-size:12px;font-family:Inter,sans-serif">
      <select onchange="buildSimRegion=this.value;renderBuildSimView()" style="height:30px;border:1px solid var(--border);border-radius:5px;padding:0 8px;font-size:12px;font-family:Inter,sans-serif">
        <option value="">Toutes les régions</option>
        ${allRegions.map(r=>`<option value="${r}" ${buildSimRegion===r?'selected':''}>${r}</option>`).join('')}
      </select>
      <div style="font-size:11px;color:var(--text3)">${Object.keys(distSwings).filter(k=>Object.values(distSwings[k]||{}).some(v=>v!==0)).length + Object.keys(guaranteedSeats).filter(k=>Object.keys(guaranteedSeats[k]||{}).length>0).length} circonscription(s) modifiées</div>
    </div>
  </div>`;

  // If editing a district, show editor
  if(buildSimEditDist){
    const eName=buildSimEditDist;
    const eD=D[eName];
    const eTo=TO_MAP[eName]||{};
    if(!eD){buildSimEditDist=null;renderBuildSimView();return;}
    const tot=Object.values(eD.v).reduce((a,b)=>a+b,0)||1;
    const gSeats=guaranteedSeats[eName]||{};
    const dSw=distSwings[eName]||{};
    const toAdj=distToAdj[eName]||{};
    const commData=COMM_SCORES[eName]||[];
    const ALL_PARTIES=[...MAJOR,'JSAP'];

    const editorHtml=`
    ${headerHtml}
    <div class="card" style="border:2px solid var(--teal);margin-bottom:10px">
      <div style="display:flex;align-items:center;gap:10px;margin-bottom:12px">
        <button onclick="buildSimEditDist=null;renderBuildSimView()" style="padding:5px 12px;background:var(--surface2);border:1px solid var(--border);border-radius:5px;font-size:12px;cursor:pointer;font-family:Inter,sans-serif">← Retour</button>
        <div style="font-size:14px;font-weight:700;color:var(--teal)">${eName}</div>
        <div style="font-size:11px;color:var(--text3)">${eD.r} · ${eD.s} sièges · TO ${((eTo.to21||0.45)*100).toFixed(0)}% · ${eD.u?'Urbain':'Rural'}</div>
        <button onclick="saveBuildSimDist('${eName.replace(/'/g,"\\'")}')" style="margin-left:auto;padding:6px 18px;background:var(--teal);color:#fff;border:none;border-radius:6px;font-size:12px;font-weight:700;cursor:pointer;font-family:Inter,sans-serif">✓ Sauvegarder</button>
      </div>

      <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:14px">

        <!-- Col 1: Guaranteed seats -->
        <div>
          <div style="font-size:11px;font-weight:700;color:var(--text3);text-transform:uppercase;letter-spacing:.07em;margin-bottom:8px">🔒 Sièges garantis</div>
          <div style="font-size:10px;color:var(--text2);margin-bottom:8px">Forcer l'attribution d'un siège à un parti, quelle que soit la simulation.</div>
          ${ALL_PARTIES.map(p=>{
            const cur=gSeats[p]||0;
            return`<div style="display:flex;align-items:center;gap:8px;padding:5px 0;border-bottom:1px solid var(--border)">
              <div style="width:8px;height:8px;border-radius:2px;background:${pc(p)};flex-shrink:0"></div>
              <span style="font-size:12px;font-weight:600;color:${pc(p)};min-width:38px">${p}</span>
              <div style="display:flex;align-items:center;gap:4px;margin-left:auto">
                <button onclick="adjGuaranteed('${eName.replace(/'/g,"\\'")}','${p}',-1)" style="width:22px;height:22px;border:1px solid var(--border);border-radius:4px;background:var(--surface2);cursor:pointer;font-size:13px;font-family:Inter,sans-serif">−</button>
                <span style="min-width:18px;text-align:center;font-size:12px;font-weight:700;color:${cur>0?pc(p):'var(--text3)'}" id="guar-val-${eName.replace(/[^a-z0-9]/gi,'')}-${p}">${cur}</span>
                <button onclick="adjGuaranteed('${eName.replace(/'/g,"\\'")}','${p}',+1)" style="width:22px;height:22px;border:1px solid var(--border);border-radius:4px;background:var(--surface2);cursor:pointer;font-size:13px;font-family:Inter,sans-serif">+</button>
              </div>
            </div>`;
          }).join('')}
          <div style="font-size:10px;color:var(--text3);margin-top:6px">Total garanti: ${Object.values(gSeats).reduce((a,b)=>a+b,0)}/${eD.s} sièges</div>
        </div>

        <!-- Col 2: District vote swings -->
        <div>
          <div style="font-size:11px;font-weight:700;color:var(--text3);text-transform:uppercase;letter-spacing:.07em;margin-bottom:8px">📊 Variation des voix (pp)</div>
          <div style="font-size:10px;color:var(--text2);margin-bottom:8px">Ajuster les voix de chaque parti dans cette circonscription uniquement.</div>
          ${ALL_PARTIES.filter(p=>p==='JSAP'||(eD.v[p]!==undefined)).map(p=>{
            const v=dSw[p]||0;
            const base=eD.v[p]||0;
            const tot2=Object.values(eD.v).reduce((a,b)=>a+b,0)||1;
            const projV=p==='JSAP'?0:Math.max(0,base+v/100*tot2);
            return`<div style="padding:5px 0;border-bottom:1px solid var(--border)">
              <div style="display:flex;align-items:center;gap:6px;margin-bottom:3px">
                <div style="width:7px;height:7px;border-radius:2px;background:${pc(p)};flex-shrink:0"></div>
                <span style="font-size:12px;font-weight:600;color:${pc(p)};min-width:38px">${p}</span>
                <span style="font-size:10px;color:var(--text3);margin-left:auto">${p==='JSAP'?'force %':`${base.toLocaleString()} voix`}</span>
              </div>
              <div style="display:flex;align-items:center;gap:6px">
                <input type="range" min="${p==='JSAP'?0:-40}" max="${p==='JSAP'?20:40}" step="1" value="${v}"
                  id="dsw2-${eName.replace(/[^a-z0-9]/gi,'')}-${p}"
                  oninput="setBuildDistSwing('${eName.replace(/'/g,"\\'")}','${p}',parseInt(this.value));document.getElementById('dsw2v-${eName.replace(/[^a-z0-9]/gi,'')}-${p}').textContent=(parseInt(this.value)>=0?'+':'')+this.value+(${p==="JSAP"}?'%':'pp')"
                  style="flex:1;height:4px">
                <span id="dsw2v-${eName.replace(/[^a-z0-9]/gi,'')}-${p}" style="font-size:11px;min-width:34px;text-align:right;font-weight:700;color:${v>0?'var(--green)':v<0?'var(--red)':'var(--text3)'}">${v>=0?'+':''}${v}${p==='JSAP'?'%':'pp'}</span>
              </div>
            </div>`;
          }).join('')}
          <div style="margin-top:8px">
            <div style="font-size:10px;font-weight:700;color:var(--text3);margin-bottom:4px">Ajustement participation (pp)</div>
            <div style="display:flex;align-items:center;gap:6px">
              <input type="range" min="-20" max="20" step="1" value="${toAdj.natAdj||0}" id="to-adj-${eName.replace(/[^a-z0-9]/gi,'')}"
                oninput="setBuildToAdj('${eName.replace(/'/g,"\\'")}',parseInt(this.value));document.getElementById('to-adj-v-${eName.replace(/[^a-z0-9]/gi,'')}'). textContent=(parseInt(this.value)>=0?'+':'')+this.value+'pp'"
                style="flex:1;height:4px">
              <span id="to-adj-v-${eName.replace(/[^a-z0-9]/gi,'')}" style="font-size:11px;min-width:34px;text-align:right;font-weight:700">${(toAdj.natAdj||0)>=0?'+':''}${toAdj.natAdj||0}pp</span>
            </div>
          </div>
        </div>

        <!-- Col 3: Commune-level -->
        <div>
          <div style="font-size:11px;font-weight:700;color:var(--text3);text-transform:uppercase;letter-spacing:.07em;margin-bottom:8px">🏘 Communes — ABCD</div>
          <div style="font-size:10px;color:var(--text2);margin-bottom:8px">${commData.length} communes · Score sur élus communaux 2021</div>
          ${commData.length===0?`<div style="font-size:11px;color:var(--text3)">Données non disponibles</div>`:
          `<div style="max-height:280px;overflow-y:auto">
            ${[...commData].sort((a,b)=>b.tot_e-a.tot_e).slice(0,20).map(c=>{
              const pData=c.p||{};
              const topParties=Object.entries(pData).filter(([,v])=>v.e>0).sort((a,b)=>b[1].e-a[1].e).slice(0,4);
              return`<div style="padding:5px 0;border-bottom:1px solid var(--border)">
                <div style="font-size:10px;color:var(--text2);margin-bottom:3px" dir="rtl">${c.ar}</div>
                <div style="display:flex;gap:4px;flex-wrap:wrap">
                  ${topParties.map(([p,v])=>{
                    const bg={'A':'#f0fdf4','B':'#f0fdfa','C':'#fffbeb','D':'#f8fafc'}[v.g];
                    const cl={'A':'#059669','B':'#0891b2','C':'#d97706','D':'#94a3b8'}[v.g];
                    return`<span style="background:${bg};color:${cl};font-size:9px;font-weight:700;padding:1px 5px;border-radius:3px">${p}:${v.g}(${v.e})</span>`;
                  }).join('')}
                </div>
              </div>`;
            }).join('')}
          </div>`}
        </div>

      </div>
    </div>

    <!-- Impact preview -->
    <div class="card" style="background:var(--teal-bg)">
      <div style="font-size:11px;font-weight:700;color:var(--teal);margin-bottom:6px">Aperçu impact — sièges projetés ${eName}</div>
      ${(()=>{
        const cur=simResults&&simResults[eName]?simResults[eName].seatsSample:null;
        const base=BASELINE_SIM[eName];
        if(!base)return'<div style="font-size:11px;color:var(--text3)">Lancez la simulation pour voir l\'impact</div>';
        return`<div style="display:flex;gap:10px;flex-wrap:wrap">
          ${Object.entries(base.meanSeats||{}).filter(([,v])=>v>0.05).sort((a,b)=>b[1]-a[1]).map(([p,v])=>`
            <div style="text-align:center">
              <div style="font-size:9px;color:var(--text3);margin-bottom:3px">${p}</div>
              <div style="font-size:14px;font-weight:700;color:${pc(p)}">${(v*eD.s).toFixed(1)}</div>
              <div style="font-size:9px;color:var(--text3)">baseline</div>
            </div>`).join('')}
        </div>
        <div style="font-size:10px;color:var(--text2);margin-top:6px">Lancez la simulation après modification pour voir l'impact exact sur les sièges.</div>`;
      })()}
    </div>`;

    document.getElementById('view-content').innerHTML=editorHtml;
    return;
  }

  // List view — all districts grouped by region
  const regions=buildSimRegion?[buildSimRegion]:[...new Set(Object.values(D).map(d=>d.r))].sort();
  const searchLower=buildSimSearch.toLowerCase();

  const listHtml=regions.map(region=>{
    const dists=Object.entries(D)
      .filter(([n,d])=>d.r===region&&(!searchLower||n.toLowerCase().includes(searchLower)))
      .sort((a,b)=>a[0].localeCompare(b[0]));
    if(!dists.length)return'';
    return`<div style="margin-bottom:14px">
      <div style="font-size:10px;font-weight:700;color:var(--text3);text-transform:uppercase;letter-spacing:.08em;padding:6px 0;border-bottom:2px solid var(--teal);margin-bottom:8px">${region}</div>
      <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(300px,1fr));gap:8px">
        ${dists.map(([name,d])=>{
          const to=TO_MAP[name]||{};
          const tot=Object.values(d.v).reduce((a,b)=>a+b,0)||1;
          const sorted=Object.entries(d.v).sort((a,b)=>b[1]-a[1]);
          const hasOverrides=Object.values(distSwings[name]||{}).some(v=>v!==0)||Object.keys(guaranteedSeats[name]||{}).length>0;
          const simW=simResults&&simResults[name]?simResults[name].seatsSample:null;
          const baseW=BASELINE_SIM[name]?.seats||[];
          const projWinner=simW?[...new Set(simW)].sort((a,b)=>simW.filter(x=>x===b).length-simW.filter(x=>x===a).length)[0]:baseW[0]||d.w21;
          const gSeats=guaranteedSeats[name]||{};
          const dSw=distSwings[name]||{};

          return`<div style="background:var(--surface);border:1px solid ${hasOverrides?'var(--teal)':'var(--border)'};border-radius:8px;padding:10px;position:relative">
            ${hasOverrides?`<div style="position:absolute;top:8px;right:8px;background:var(--teal);color:#fff;font-size:9px;font-weight:700;padding:2px 6px;border-radius:10px">MODIFIÉ</div>`:''}
            <div style="font-size:13px;font-weight:700;color:var(--navy);margin-bottom:4px;padding-right:${hasOverrides?60:0}px">${name}</div>
            <div style="font-size:10px;color:var(--text3);margin-bottom:6px">${d.s} sièges · TO ${((to.to21||0.45)*100).toFixed(0)}% · ${d.u?'Urbain':'Rural'} · Marge +${d.m}pp</div>
            
            <!-- Vote bar -->
            <div class="seat-bar" style="height:6px;margin-bottom:6px;border-radius:3px;overflow:hidden">
              ${sorted.slice(0,6).map(([p,v])=>`<div style="width:${(v/tot*100).toFixed(1)}%;background:${pc(p)}" title="${p}: ${v.toLocaleString()}"></div>`).join('')}
            </div>
            
            <!-- Top parties -->
            <div style="display:flex;gap:4px;flex-wrap:wrap;margin-bottom:6px">
              ${sorted.slice(0,5).map(([p,v],i)=>`<span style="font-size:10px;font-weight:${i<d.s?700:400};color:${i<d.s?pc(p):'var(--text3)'}${i<d.s?';text-decoration:underline;text-decoration-color:'+pc(p)+';text-underline-offset:2px':''}">${p} ${(v/tot*100).toFixed(0)}%</span>`).join('<span style="color:var(--border2)">·</span>')}
            </div>

            <!-- History chips -->
            <div style="display:flex;gap:4px;margin-bottom:8px;flex-wrap:wrap">
              ${['2011','2016','2021'].map(yr=>{
                const w=d['w'+yr.slice(2)];
                return w?`<span style="font-size:9px;background:${pc(w)}22;color:${pc(w)};padding:1px 5px;border-radius:3px;font-weight:600">${yr}: ${w}</span>`:'';
              }).join('')}
              <span style="font-size:9px;background:var(--teal-bg);color:var(--teal);padding:1px 5px;border-radius:3px;font-weight:700">2026: ${projWinner||'?'}</span>
            </div>

            <!-- Override summary if any -->
            ${hasOverrides?`<div style="background:var(--teal-bg);border-radius:5px;padding:5px 7px;font-size:10px;margin-bottom:6px">
              ${Object.entries(dSw).filter(([,v])=>v!==0).map(([p,v])=>`<span style="color:${pc(p)};font-weight:600">${p}:${v>=0?'+':''}${v}pp </span>`).join('')}
              ${Object.entries(gSeats).filter(([,n])=>n>0).map(([p,n])=>`<span style="color:${pc(p)};font-weight:600">🔒${p}×${n} </span>`).join('')}
            </div>`:''}

            <button onclick="buildSimEditDist='${name.replace(/'/g,"\\'")}';renderBuildSimView()" 
              style="width:100%;padding:6px;background:${hasOverrides?'var(--teal)':'var(--surface2)'};color:${hasOverrides?'#fff':'var(--text2)'};border:1px solid ${hasOverrides?'var(--teal)':'var(--border)'};border-radius:5px;font-size:11px;font-weight:600;cursor:pointer;font-family:Inter,sans-serif">
              ${hasOverrides?'✏ Modifier la simulation':'⚙ Construire simulation'}
            </button>
          </div>`;
        }).join('')}
      </div>
    </div>`;
  }).join('');

  document.getElementById('view-content').innerHTML=headerHtml+`<div style="margin-top:4px">`+listHtml+`</div>`;
}

function setBuildDistSwing(name,party,val){
  if(!distSwings[name])distSwings[name]={};
  if(party==='JSAP'){jsapForce=Math.max(0,Math.min(20,val));}
  else distSwings[name][party]=val;
}

function setBuildToAdj(name,val){
  if(!distToAdj[name])distToAdj[name]={};
  distToAdj[name].natAdj=val;
}

function adjGuaranteed(name,party,delta){
  if(!guaranteedSeats[name])guaranteedSeats[name]={};
  const cur=guaranteedSeats[name][party]||0;
  const d=D[name];
  const maxSeats=d?d.s:10;
  const newVal=Math.max(0,Math.min(maxSeats,cur+delta));
  if(newVal===0)delete guaranteedSeats[name][party];
  else guaranteedSeats[name][party]=newVal;
  const el=document.getElementById('guar-val-'+name.replace(/[^a-z0-9]/gi,'')+'-'+party);
  if(el)el.textContent=newVal;
}

function saveBuildSimDist(name){
  buildSimEditDist=null;
  renderBuildSimView();
}

function loadBaselineSim(){
  // Populate distSwings from BASELINE_SIM seats
  // This is informational — sliders stay at 0, we just show baseline is active
  simResults=BASELINE_SIM;
  renderBuildSimView();
  // Flash feedback
  const btn=document.querySelector('[onclick="loadBaselineSim()"]');
  if(btn){btn.textContent='✓ Baseline chargé';setTimeout(()=>{btn.textContent='📊 Charger forecast baseline';},1500);}
}

function resetAllOverrides(){
  distSwings={};MAJOR.forEach(p=>{swings[p]=0;});
  guaranteedSeats={};distToAdj={};jsapForce=0;
  simResults=BASELINE_SIM;
  renderBuildSimView();
}

function applyBuildSim(){
  // Apply distToAdj turnout adjustments then run simulation
  // Patch getEffTO to use distToAdj
  runSim();
  buildSimEditDist=null;
  setTopTab('simdetails');
}

// ── PDF EXPORT ──────────────────────────────────────────────────────────────
async function exportPDF(){
  const btn = document.getElementById('pdf-export-btn');
  if(btn){ btn.textContent='Generating…'; btn.disabled=true; }
  try{
    const seats = getSeats();
    const payload = {
      national: seats,
      ci: BASELINE_SIM._ci||{},
      ci_lo: BASELINE_SIM._ci_lo||{},
      ci_hi: BASELINE_SIM._ci_hi||{},
      runs: BASELINE_SIM._runs||10000,
      label: BASELINE_SIM._label||'2026 Forecast',
      districts: Object.entries(D).map(([name,d])=>{
        const sim = simResults&&simResults[name];
        return {
          name, seats:d.s, w21:d.w21, region:d.r,
          projected: sim ? sim.seats||[] : [],
          meanSeats: sim ? sim.meanSeats||{} : {},
        };
      })
    };
    const res = await fetch('/api/report', {
      method:'POST',
      headers:{'Content-Type':'application/json','Authorization':'Bearer '+sessionStorage.getItem('intelx_s')},
      body: JSON.stringify(payload)
    });
    if(!res.ok) throw new Error(await res.text());
    const blob = await res.blob();
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href=url; a.download='intelX_Simulation_Report_2026.pdf';
    a.click(); URL.revokeObjectURL(url);
  } catch(err){
    alert('PDF generation failed: '+err.message);
  } finally{
    if(btn){ btn.textContent='Export PDF'; btn.disabled=false; }
  }
}

// Auto-boot: when app.js finishes loading, init if session exists
(function(){
  // Session key is set by index.html when password is correct
  // Just check it exists — the password was already validated at login
  const sk = sessionStorage.getItem('intelx_s');
  if(sk) {
    const overlay = document.getElementById('login-overlay');
    if(overlay) overlay.classList.add('hidden');
    init();
  }
})();
